import React, { useEffect, useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import "./Appraisal.css";

const Appraisal = () => {
  const [appraisals, setAppraisals] = useState([]);
  const navigate = useNavigate();
  const location = useLocation();

  /* =========================
     Determine Route Base
  ========================= */
  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || {};

  const base =
    loggedUser?.role?.toUpperCase() === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* =========================
     Load Data
  ========================= */
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("appraisals")) || [];

    if (stored.length === 0) {
      const sample = [
        {
          id: 1,
          employeeName: "Rahul R",
          department: "IT",
          period: "Jan 2024 - Dec 2024",
          rating: 4.5,
          status: "Approved",
        },
        {
          id: 2,
          employeeName: "Sneha K",
          department: "HR",
          period: "Jan 2024 - Dec 2024",
          rating: 4.2,
          status: "Pending",
        },
        {
          id: 3,
          employeeName: "David M",
          department: "Finance",
          period: "Jan 2024 - Dec 2024",
          rating: 3.8,
          status: "Rejected",
        },
      ];

      localStorage.setItem("appraisals", JSON.stringify(sample));
      setAppraisals(sample);
    } else {
      setAppraisals(stored);
    }
  }, [location]);

  /* =========================
     Actions
  ========================= */
  const handleDelete = (id) => {
    if (!window.confirm("Delete this appraisal?")) return;

    const filtered = appraisals.filter((a) => a.id !== id);
    setAppraisals(filtered);
    localStorage.setItem("appraisals", JSON.stringify(filtered));
  };

  const handleAdd = () =>
    navigate(`${base}/appraisal/add`);

  const handleView = (id) =>
    navigate(`${base}/appraisal/view/${id}`);

  const handleEdit = (id) =>
    navigate(`${base}/appraisal/edit/${id}`);

  const getStatusClass = (status) => {
    switch (status) {
      case "Approved":
        return "status-approved";
      case "Pending":
        return "status-pending";
      case "Rejected":
        return "status-rejected";
      default:
        return "";
    }
  };

  /* =========================
     UI
  ========================= */
  return (
    <div className="appraisal-scope">
      <div className="appraisal-container">

        <h2 className="appraisal-title">Employee Appraisals</h2>

        <div className="appraisal-header">
          <button className="add-btn" onClick={handleAdd}>
            Add New Appraisal
          </button>
        </div>

        <table className="appraisal-table">
          <thead>
            <tr>
              <th>S No</th>
              <th>Employee Name</th>
              <th>Department</th>
              <th>Review Period</th>
              <th>Rating</th>
              <th>Status</th>
              <th style={{ textAlign: "center" }}>Actions</th>
            </tr>
          </thead>

          <tbody>
            {appraisals.length === 0 ? (
              <tr>
                <td colSpan="7" style={{ textAlign: "center" }}>
                  No Appraisals Found
                </td>
              </tr>
            ) : (
              appraisals.map((item, index) => (
                <tr key={item.id}>
                  <td>{index + 1}</td>
                  <td>{item.employeeName}</td>
                  <td>{item.department}</td>
                  <td>{item.period}</td>
                  <td>{item.rating}</td>

                  <td>
                    <span className={`status-badge ${getStatusClass(item.status)}`}>
                      {item.status}
                    </span>
                  </td>

                  <td className="action-col">
                    <button
                      className="view-btn"
                      onClick={() => handleView(item.id)}
                    >
                      View
                    </button>

                    <button
                      className="edit-btn"
                      onClick={() => handleEdit(item.id)}
                    >
                      Edit
                    </button>

                    <button
                      className="delete-btn"
                      onClick={() => handleDelete(item.id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

      </div>
    </div>
  );
};

export default Appraisal;
